    id: "RULE_ART_0219",
    subject: "Application",
    contextLocation: "Ontario",
    constraintType: "Required",
    value: "This Subsection shall apply to the storage of ammonium nitrate in quantities exceeding 1000 kg in the form of crystals, flakes, grains or prills, including fertilizer grade or other mixtures containing 60% or more ammonium nitrate by weight, but does not apply to blasting agents or fertilizer storage on railways regulated by the Canadian Transport Commission.",
    buildingType: "All",
    sectionReference: "OFC 3.3.3.1",
    condition: "Division B, Part 3, Section 3.3, Subsection 3.3.3.",
    severity: "Major",
