    id: "RULE_ART_0289",
    subject: "Rooms or enclosed spaces",
    contextLocation: "Ontario",
    constraintType: "Required",
    value: "Where flammable liquids or combustible liquids are processed, handled, stored, dispensed or used within rooms or enclosed spaces, ventilation shall conform to this Part and the Building Code.",
    buildingType: "All",
